const body = $input.first().json.body || {};

if (body.type === 'url_verification' && body.challenge) {
  return [{ json: { mode: 'challenge', challenge: body.challenge } }];
}

const event = body.event || {};
if (event.bot_id || event.subtype === 'bot_message') return [];

if (event.type === 'reaction_added' && event.item) {
  return [{
    json: {
      mode: 'reaction',
      reaction: event.reaction,
      channel: event.item.channel,
      message_ts: event.item.ts,
      user: event.user || ''
    }
  }];
}

const text = event.text || '';
const isMention = text.includes('<@');
if (!event.thread_ts && !isMention) return [];

return [{
  json: {
    mode: 'event',
    channel: event.channel,
    thread_ts: event.thread_ts || event.ts,
    ts: event.ts || event.thread_ts,
    text,
    user: event.user || '',
    is_mention: isMention
  }
}];

if ($json.mode !== 'event') return [];

const channel = $json.channel;
const text = ($json.text || '').toLowerCase();
const isDecision = channel === 'C0AM2310P8A' && /(log this|decided:)/i.test(text);
const isInfraStatus = channel === 'C0ALVM4PAE7' && /\b(status|health|how.s|infra|check|systems?)\b/i.test(text);

const channelPersonaMap = {
  C0ALLEKR9FZ: { name: 'Engineering', icon: ':mage:', prompt: 'You are the Staff Engineer for Paperwork Labs. Stack: Next.js 16 + Tailwind v4 + shadcn/ui (frontend), FastAPI + SQLAlchemy + Neon PostgreSQL (backend). Monorepo: apps/filefree, apps/launchfree, apps/studio, apps/trinkets, apps/distill + apis/. Give practical implementation guidance, call out risks, keep answers concise. If reviewing a PR, include risks and test recommendations. Never suggest AWS — we use GCP + Render + Vercel.', docs: ['TASKS'] },
  C0ALLJWR1HV: { name: 'EA / Operator', icon: ':astronaut:', prompt: 'You are the EA / Operator for Paperwork Labs. Products: FileFree (tax, filefree.ai), LaunchFree (LLC, launchfree.ai), Distill (B2B, distill.tax), Trinkets (tools). Two co-founders: F1 (Product/Eng), F2 (Partnerships). Monthly burn ~$278. Provide clear operational guidance, reference active task phases, surface blockers, suggest next actions. Keep responses mobile-friendly.', docs: ['TASKS', 'KNOWLEDGE'] },
  C0AM2310P8A: { name: 'Strategy', icon: ':brain:', prompt: 'You are the Strategy persona for Paperwork Labs. North Stars: FileFree MeF Transmitter (Jan 2027), LaunchFree 50-state Engine (Summer 2026), Distill B2B platform (Summer 2026). Revenue from partnerships (77%), B2B APIs, upsells. Consumer products free forever. Focus on tradeoffs, prioritization, milestone alignment.', docs: ['TASKS', 'KNOWLEDGE'] },
  C0ALLD3P3A9: { name: 'QA', icon: ':detective:', prompt: 'You are the QA persona for Paperwork Labs. Critical: never log PII, SSNs never sent to LLMs, uploads auto-delete 24hrs, rate limits on all endpoints. Tax calcs use integer math (cents). Focus on bugs, regressions, testing gaps, security risks.', docs: ['TASKS'] },
  C0AMEQV199P: { name: 'Strategy', icon: ':brain:', prompt: 'You are the Strategy persona for Paperwork Labs. Products: FileFree, LaunchFree, Distill, Trinkets. Phase 2 (FileFree product) and Phase 3 (LaunchFree) are active. Focus on high-leverage priorities and company-level execution.', docs: ['TASKS', 'KNOWLEDGE'] },
  C0AM01NHQ3Y: { name: 'Engineering', icon: ':mage:', prompt: 'You are the Engineering persona for Paperwork Labs. Stack: Next.js 16 + Tailwind + shadcn (frontend), FastAPI + SQLAlchemy + Neon PostgreSQL (backend). Infra: Vercel, Render, GCP Cloud Vision, Hetzner (n8n). Provide technically sound, executable guidance.', docs: ['TASKS'] },
  C0ALVM4PAE7: { name: 'Engineering', icon: ':gear:', prompt: 'You are the Engineering persona for Paperwork Labs, monitoring #alerts. Infrastructure: Hetzner (n8n, Postiz, 7 containers), Render (2 APIs), Vercel (5 apps), Neon (DB), Upstash (Redis). Provide clear infra guidance and troubleshooting steps.', docs: ['TASKS'] },
};

const intentPersonas = [
  { id: 'legal', regex: /(^|\b)(@?legal|counsel|compliance review|legal review)(\b|$)/i, persona: { name: 'Legal', icon: ':owl:', prompt: 'You are General Counsel for Paperwork Labs. Focus on legal risk, compliance boundaries (FTC, Circular 230, CCPA, DPA), disclosures, and policy implications. Products handle SSNs, EINs, financial data. Consumer products are free — FTC requires clear disclosure. Keep advice practical and concrete.', docs: [] } },
  { id: 'social', regex: /(^|\b)(@?social|social take|content angle|creator)(\b|$)/i, persona: { name: 'Social', icon: ':parrot:', prompt: 'You are the Social persona for Paperwork Labs. Brands: FileFree (@filefree.ai), LaunchFree (@launchfree.ai). Gen Z audience (18-30). Give distribution-focused messaging guidance, hooks, and concise copy edits. Use brand voice from brand.mdc.', docs: [] } },
  { id: 'growth', regex: /(^|\b)(@?growth|growth take|acquisition|seo|funnel)(\b|$)/i, persona: { name: 'Growth', icon: ':seedling:', prompt: 'You are the Growth persona for Paperwork Labs. Target: Gen Z first-time filers and first-time entrepreneurs. Channels: TikTok, Instagram, SEO (trinkets), Reddit. Focus on activation, acquisition, conversion, and measurable growth experiments.', docs: [] } },
  { id: 'qa', regex: /(^|\b)(@?qa|test|testing|regression|security scan)(\b|$)/i, persona: { name: 'QA', icon: ':detective:', prompt: 'You are the QA persona for Paperwork Labs. Never log PII. SSNs never sent to LLMs. All uploads auto-delete 24hrs. Tax calcs use integer math (cents). Prioritize defects, regressions, missing test coverage, and security checks.', docs: ['TASKS'] } },
  { id: 'strategy', regex: /(^|\b)(@?strategy|priorit|roadmap|tradeoff|exec)(\b|$)/i, persona: { name: 'Strategy', icon: ':brain:', prompt: 'You are the Strategy persona for Paperwork Labs. North Stars: FileFree MeF (Jan 2027), LaunchFree 50-state (Summer 2026), Distill B2B (Summer 2026). Focus on sequencing, tradeoffs, and venture-level alignment.', docs: ['TASKS', 'KNOWLEDGE'] } },
  { id: 'engineering', regex: /(^|\b)(@?engineering|@?eng|implementation|architecture|code review)(\b|$)/i, persona: { name: 'Engineering', icon: ':mage:', prompt: 'You are the Staff Engineer for Paperwork Labs. Stack: Next.js 16 + Tailwind + shadcn, FastAPI + SQLAlchemy + Neon. Monorepo with pnpm. Give direct implementation guidance, code-level risk review, and testing recommendations.', docs: ['TASKS'] } },
  { id: 'cpa', regex: /(^|\b)(@?cpa|tax advisor|tax review)(\b|$)/i, persona: { name: 'CPA Advisor', icon: ':nerd_face:', prompt: 'You are the CPA / Tax Advisor for Paperwork Labs. Focus on tax accuracy, edge cases, safe user-facing guidance. Never provide advice that crosses UPL boundaries. All calculations must match IRS Pub 17.', docs: [] } },
  { id: 'partnerships', regex: /(^|\b)(@?partnerships|partner|affiliate|bd)(\b|$)/i, persona: { name: 'Partnerships', icon: ':handshake:', prompt: 'You are the Partnerships persona for Paperwork Labs. Partnerships drive 77% of consumer revenue. Tiered strategy: A (affiliate), B (managed), C (API), D (marketplace). Focus on partner fit, outreach posture, and commercial implications.', docs: [] } },
  { id: 'cfo', regex: /(^|\b)(@?cfo|cost|spend|burn|budget)(\b|$)/i, persona: { name: 'CFO', icon: ':chart_with_upwards_trend:', prompt: 'You are the CFO for Paperwork Labs. Monthly burn ~$278. Infrastructure: Render ($21), Hetzner ($6), Vercel (free->$20). Focus on unit economics, infrastructure spend, and vendor evaluation.', docs: [] } },
  { id: 'ea', regex: /(^|\b)(@?ea|operator|ops view|briefing)(\b|$)/i, persona: { name: 'EA / Operator', icon: ':astronaut:', prompt: 'You are the EA / Operator for Paperwork Labs. Focus on execution clarity, owner/action mapping, and operational cadence. Reference active phases and recent decisions.', docs: ['TASKS', 'KNOWLEDGE'] } }
];

const override = intentPersonas.find((entry) => entry.regex.test(text));
const defaultPersona = channelPersonaMap[channel] || channelPersonaMap.C0AM01NHQ3Y;
const persona = override ? override.persona : defaultPersona;

return [{
  json: {
    ...$json,
    route: isDecision ? 'decision' : isInfraStatus ? 'infra-status' : 'reply',
    persona_name: persona.name,
    persona_icon: persona.icon,
    persona_prompt: persona.prompt,
    persona_docs: persona.docs || [],
    persona_override: override ? override.id : null
  }
}];

const routed = $('Route Persona').first().json;
const thread = $('Fetch Thread History').first().json;
const messages = (thread.messages || []).slice(-20).map((m) => `${m.user || 'bot'}: ${m.text || ''}`).join('\n');

const docNames = routed.persona_docs || [];
let docsContext = '';

if (docNames.length > 0) {
  const ghToken = $env.GITHUB_TOKEN || '';
  const headers = { Accept: 'application/vnd.github.v3.raw', 'User-Agent': 'n8n-paperwork' };
  if (ghToken) headers.Authorization = `Bearer ${ghToken}`;

  for (const doc of docNames) {
    try {
      const url = `https://api.github.com/repos/paperwork-labs/paperwork/contents/docs/${doc}.md`;
      const resp = await this.helpers.httpRequest({ method: 'GET', url, headers });
      let content = typeof resp === 'string' ? resp : JSON.stringify(resp);

      if (doc === 'TASKS') {
        const lines = content.split('\n');
        const trimmed = [];
        let keep = true, hdr = false;
        for (const l of lines) {
          if (l.startsWith('## Phase') || l.startsWith('## Section')) { hdr = true; keep = !/COMPLETE|completed|100%/i.test(l); }
          if (!hdr || keep) trimmed.push(l);
        }
        content = trimmed.join('\n').slice(0, 8000);
      } else if (doc === 'KNOWLEDGE') {
        const fac = []; let inF = false;
        for (const l of content.split('\n')) {
          if (/^#.*Front.and.Center/i.test(l)) inF = true;
          if (inF) { fac.push(l); if (fac.length > 1 && /^---/.test(l)) break; }
        }
        const blocks = content.split(/(?=^### D\d+)/m);
        content = (fac.join('\n') + '\n--- Recent ---\n' + blocks.slice(-10).join('\n')).slice(0, 5000);
      } else {
        content = content.slice(0, 5000);
      }
      docsContext += `\n--- ${doc}.md ---\n${content}\n`;
    } catch (e) { docsContext += `\n[Could not fetch ${doc}.md]\n`; }
  }
}

const docSection = docsContext ? `\n\nRelevant docs for context:\n${docsContext}` : '';
const userPrompt = `Channel: ${routed.channel}\nThread TS: ${routed.thread_ts}\nLatest message: ${routed.text}\n\nRecent thread context:\n${messages}${docSection}\n\nRespond in Slack mrkdwn only: use *bold* (never **bold**) and <url|text> (never [text](url)). Keep it concise and actionable.`;

return [{
  json: {
    channel: routed.channel,
    thread_ts: routed.thread_ts,
    persona_name: routed.persona_name,
    persona_icon: routed.persona_icon,
    system_prompt: routed.persona_prompt,
    user_prompt: userPrompt
  }
}];

function sanitizeSlackMrkdwn(text) {
  return String(text || '')
    .replace(/```\w*\n?/g, '```')
    .replace(/^#{1,6}\s+(.+)$/gm, '*$1*')
    .replace(/^[-*_]{3,}\s*$/gm, '')
    .replace(/\*\*(.+?)\*\*/g, '*$1*')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<$2|$1>')
    .replace(/\n{3,}/g, '\n\n');
}

const routed = $('Build Thread Context').first().json;
const output = $json.output || [];
const aiText = output[0]?.content?.find((part) => part.type === 'output_text')?.text;

const errorMessage = (
  $json.error?.message ||
  $json.error?.description ||
  $json.message ||
  ''
);

let text = aiText;
if (!text) {
  const err = String(errorMessage).toLowerCase();

  if (err.includes('insufficient_quota') || err.includes('exceeded your current quota')) {
    text = ':warning: AI response unavailable: OpenAI quota is exhausted for this workspace. Please top up billing, then retry this thread message.';
  } else if (err.includes('rate') || err.includes('429')) {
    text = ':warning: AI response unavailable: OpenAI rate limit hit. Please retry in 30-60 seconds.';
  } else if (err.includes('incorrect api key') || err.includes('invalid_api_key') || err.includes('unauthorized') || err.includes('401')) {
    text = ':warning: AI response unavailable: OpenAI credential is invalid. Please update the n8n OpenAI credential and retry.';
  } else {
    text = ':warning: AI response unavailable right now. Most likely cause is model quota or billing limits. Please top up/check OpenAI billing, then retry this thread.';
  }
}

text = sanitizeSlackMrkdwn(text);

return [{
  json: {
    channel: routed.channel,
    thread_ts: routed.thread_ts,
    text,
    username: routed.persona_name,
    icon_emoji: routed.persona_icon
  }
}];

if ($json.mode !== 'reaction') return [];
if ($json.channel !== 'C0ALLEKR9FZ') return [];

const actionMap = {
  white_check_mark: 'merge',
  rocket: 'merge',
  eyes: 'review',
  no_entry_sign: 'hold'
};

const action = actionMap[$json.reaction];
if (!action) return [];

return [{
  json: {
    channel: $json.channel,
    message_ts: $json.message_ts,
    reaction: $json.reaction,
    action
  }
}];

const slackResp = $input.first().json;
const messages = slackResp.messages || [];
if (!messages.length) return [];

const msgText = messages[0].text || '';
const msgTs = messages[0].ts || '';
const routed = $('Route Reaction Events').first().json;
const channel = routed.channel;
const action = routed.action;

const prMatch = msgText.match(/github\.com\/[^\/]+\/[^\/]+\/pull\/(\d+)/);
if (!prMatch) return [];

const prNumber = parseInt(prMatch[1], 10);
const owner = 'paperwork-labs';
const repo = 'paperwork';

const githubToken = $env.GITHUB_TOKEN || '';
const ghHeaders = {
  Accept: 'application/vnd.github.v3+json',
  'User-Agent': 'n8n-paperwork'
};
if (githubToken) {
  ghHeaders.Authorization = `Bearer ${githubToken}`;
}

const slackBotToken = $env.SLACK_BOT_TOKEN || '';
const slackPost = async (text) => {
  if (!slackBotToken) return;
  await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://slack.com/api/chat.postMessage',
    headers: { Authorization: `Bearer ${slackBotToken}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ channel, text, thread_ts: msgTs, username: 'Engineering', icon_emoji: ':mage:' })
  });
};

if (action === 'hold') {
  await slackPost(`:no_entry_sign: PR #${prNumber} merge held by founder.`);
  return [];
}

if (action === 'review') {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: `https://api.github.com/repos/${owner}/${repo}/pulls/${prNumber}/requested_reviewers`,
      headers: { ...ghHeaders, 'Content-Type': 'application/json' },
      body: JSON.stringify({ reviewers: ['copilot-pull-request-reviewer[bot]'] })
    });
    await slackPost(`:eyes: Copilot re-review requested for PR #${prNumber}.`);
  } catch (e) {
    const reason = e.message || 'unknown error';
    await slackPost(`:warning: Failed to request Copilot review for PR #${prNumber}: ${reason}`);
  }
  return [];
}

const prResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://api.github.com/repos/${owner}/${repo}/pulls/${prNumber}`,
  headers: ghHeaders
});

const sha = prResp.head.sha;

const checksResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://api.github.com/repos/${owner}/${repo}/commits/${sha}/check-runs`,
  headers: ghHeaders
});

const runs = checksResp.check_runs || [];
const notReady = runs.filter(c =>
  c.name !== 'auto-merge' &&
  !(c.status === 'completed' && ['success', 'skipped', 'neutral'].includes(c.conclusion))
);

if (notReady.length > 0) {
  const blockers = notReady.map(c =>
    c.status !== 'completed' ? `${c.name} (${c.status})` : `${c.name} (${c.conclusion})`
  );
  await slackPost(`:x: CI not green yet — ${blockers.join(', ')}`);
  return [];
}

return [{
  json: {
    pr_number: prNumber,
    sha,
    channel,
    message_ts: msgTs,
    pr_title: prResp.title || `#${prNumber}`,
    pr_url: prResp.html_url || `https://github.com/${owner}/${repo}/pull/${prNumber}`
  }
}];

const apiKey = $env.N8N_API_KEY;
let total = 0, active = 0, inactiveNames = [], liveness = '000';

try {
  const resp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'http://localhost:5678/api/v1/workflows?limit=250',
    headers: { 'X-N8N-API-KEY': apiKey },
  });
  liveness = '200';
  const workflows = resp.data || [];
  total = workflows.length;
  active = workflows.filter(w => w.active).length;
  inactiveNames = workflows.filter(w => !w.active).map(w => w.name);
} catch (e) {
  // n8n REST API unreachable or auth failed
}

const statusEmoji = (active === total && liveness === '200') ? ':white_check_mark:' : ':warning:';
const inactiveSection = inactiveNames.length > 0
  ? `\n\nInactive workflows:\n${inactiveNames.map(n => `• ${n}`).join('\n')}`
  : '';

const message = `${statusEmoji} *n8n Infrastructure Status*\n\n` +
  `• Workflows: ${active}/${total} active\n` +
  `• n8n liveness: ${liveness}` +
  inactiveSection;

return [{
  json: {
    total,
    active,
    inactive: total - active,
    inactiveNames,
    liveness,
    message,
    channel: $json.channel,
    thread_ts: $json.thread_ts
  }
}];
